// if that edge is not defined in the schema.
func (m *PetMutation) ClearEdge(name string) error {
	switch name {
	case "team":
		m.ClearTeam()
		return nil
	case "owner":
		m.ClearOwner()
		return nil
	}
	return fmt.Errorf("unknown Pet unique edge %s", name)
}

// ResetEdge resets all changes to the edge with the given name in this mutation.
// It returns an error if the edge is not defined in the schema.
func (m *PetMutation) ResetEdge(name string) error {
	switch name {
	case "team":
		m.ResetTeam()
		return nil
	case "owner":
		m.ResetOwner()
		return nil
	}
	return fmt.Errorf("unknown Pet edge %s", name)
}

// Exported accessors for cross-package CUD builders.
// SetMutationID sets the tracked entity ID after a successful create.
func (m *PetMutation) SetMutationID(id *int) { m.id = id }

// SetDone marks the mutation as completed.
func (m *PetMutation) SetDone() { m.done = true }

// MutationPredicates returns the list of predicates for update/delete mutations.
func (m *PetMutation) MutationPredicates() []predicate.Pet { return m.predicates }

// AddPredicate adds a predicate to the mutation (used by entql filters).
func (m *PetMutation) AddPredicate(pred func(s *sql.Selector)) {
	m.predicates = append(m.predicates, pred)
}
